#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    getchar();
    while (T--) {
        char s[1005];
        fgets(s, sizeof(s), stdin);
        s[strcspn(s, "\n")] = '\0';
        if (strlen(s) > 0) {
            printf("%c\n", s[strlen(s) - 1]);
        } else {
            printf("\n");
        }
    }
    return 0;
}

