code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let T;
let i = 0;
let output = [];
rl.on('line', (line) => {
    if (typeof T === 'undefined') {
        T = parseInt(line, 10);
    } else {
        const s = line.trim();
        if (s) {
            output.push(s[s.length - 1]);
        } else {
            output.push('');
        }
        i++;
        if (i === T) {
            console.log(output.join('\n'));
            rl.close();
        }
    }
});
